from collections import deque

def shortest_path(edges, start, end):
    if start == end:
        return [start]

    neighbors = {}
    for q1, q2 in edges:
        neighbors.setdefault(q1, []).append(q2)
        neighbors.setdefault(q2, []).append(q1)

    visited = {start}
    queue = deque([(start, [start])])

    while queue:
        node, path = queue.popleft()
        for neighbor in neighbors.get(node, []):
            if neighbor == end:
                return path + [end]
            if neighbor not in visited:
                visited.add(neighbor)
                queue.append((neighbor, path + [neighbor]))

    return []

edges = {(0, 1), (1, 2), (2, 3)}
print(shortest_path(edges, 0, 3))

def apply_swap(pq1, pq2, mapping):
    new_mapping = dict(mapping)
    reverse = {v: k for k, v in mapping.items()}

    lq1 = reverse.get(pq1)
    lq2 = reverse.get(pq2)

    if lq1 is not None:
        new_mapping[lq1] = pq2
    if lq2 is not None:
        new_mapping[lq2] = pq1

    return new_mapping

mapping = {0: 0, 1: 1, 2: 2}
print(apply_swap(0, 1, mapping))

def basic_route(gate, mapping, edges):
    name, (lq1, lq2) = gate
    pq1, pq2 = mapping[lq1], mapping[lq2]

    if (pq1, pq2) in edges or (pq2, pq1) in edges:
        return [(name, (pq1, pq2))], mapping

    # Find shortest path
    from collections import deque
    neighbors = {}
    for q1, q2 in edges:
        neighbors.setdefault(q1, []).append(q2)
        neighbors.setdefault(q2, []).append(q1)

    visited = {pq1}
    queue = deque([(pq1, [pq1])])
    path = []
    while queue:
        node, p = queue.popleft()
        if node == pq2:
            path = p
            break
        for n in neighbors.get(node, []):
            if n not in visited:
                visited.add(n)
                queue.append((n, p + [n]))

    # Insert SWAPs and update mapping
    gates = []
    new_mapping = dict(mapping)
    reverse = {v: k for k, v in mapping.items()}

    current = pq1
    for next_pos in path[1:-1]:
        gates.append(('SWAP', (current, next_pos)))
        # Update mapping
        lqa = reverse.get(current)
        lqb = reverse.get(next_pos)
        if lqa: new_mapping[lqa] = next_pos
        if lqb: new_mapping[lqb] = current
        reverse[current], reverse[next_pos] = lqb, lqa
        current = next_pos

    gates.append((name, (current, pq2)))
    return gates, new_mapping

mapping = {0: 0, 1: 2}
edges = {(0, 1), (1, 2)}
print(basic_route(('CX', (0, 1)), mapping, edges))
